-- ai_overview.sql — UPDATE ai_overview + ai_overview_details, keyed (family, root_cause_id)
BEGIN;
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is elevated latency on downstream API services — due to conditions such as resource exhaustion, misconfigured connection pools, or missing database indexes — exceeding the Integration Gateway''s configured timeout and producing HTTP 504 errors.", "key_points": ["**Common pattern:** Scheduled data synchronization jobs fail with repeated HTTP 504 Gateway Timeout responses, typically clustering during overnight or early-morning batch windows. Gateway dashboards show downstream p95/p99 latency spiking from a baseline of ~200 ms–3 s to 7–72 s, well beyond the configured timeout. Retry exhaustion and message queue backlogs follow, delaying dependent workflows such as finance reporting and billing integrations. Authentication errors (401/403) and rate limiting (429) are consistently absent from logs.", "**Scope / variation:** Gateway timeout thresholds vary across environments (2–5 seconds up to 30 seconds), so failures surface at different downstream latency levels. Both internal services and external third-party APIs are affected with identical timeout behavior. In one instance, a recent gateway deployment introduced intermittent 401 errors alongside the dominant 504 pattern, but the 504s persisted independently after token rotation. Queue backlog severity ranges widely, from sync lag of 45+ minutes to over 4,200 pending messages.", "**How it''s identified:** Gateway logs and distributed traces confirm that downstream response times exceed the configured timeout window while showing no evidence of authentication failures or throttling. Resolution consistently requires the downstream API team to address a backend performance condition — such as a misconfigured connection pool or a missing database index — rather than any gateway-side action like pod restarts, cache clears, or token rotation."], "confidence": "high", "evidence": {"ticket_count": 23, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:53:16.169753+00:00"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/downstream-api-latency-exceeds-timeout';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause of HTTP 504 Gateway Timeout failures in integration jobs may be downstream API rate-limit enforcement (HTTP 429) compounded by the gateway''s retry-stacking behavior.", "key_points": ["**Common pattern:** Scheduled and real-time integration jobs begin failing with HTTP 504 errors; monitoring shows sharply rising downstream latency and elevated error rates, yet the external endpoint responds normally to individual test calls — suggesting volume-driven throttling rather than a full outage.", "**Scope / variation:** HTTP 401 Unauthorized errors may also appear in early logs, potentially misdirecting investigation toward credential issues. Both real-time sync and batch ingestion jobs sharing the same gateway path and API quota could be affected simultaneously, and the gateway worker queue backlog may continue growing even after the initial throttling event as retries compound with new requests."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:53:22.590475+00:00"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/downstream-rate-limiting-throttling';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is an expired API token on the Integration Gateway, resulting in HTTP 401 errors, cascading retry-driven 504 timeouts, and stalled data synchronization jobs.", "key_points": ["**Common pattern:** Scheduled sync jobs fail during overnight or early-morning batch windows. Gateway logs show HTTP 401 Unauthorized responses with token-expired indicators, followed by exponential-backoff retries that culminate in 504 Gateway Timeout errors. Downstream workflows—including CRM sync, order fulfillment, and finance reconciliation—stall, and dependent dashboards display stale or missing data.", "**Scope / variation:** The issue has been observed across multiple regions, infrastructure types (standalone hosts and Kubernetes pods), and environments (staging and production simultaneously when a shared service account token is used). In some incidents, only 504 errors are visible initially, with 401 errors surfacing only in deeper log analysis; retry storms may also produce HTTP 429 rate-limiting responses. Silent failures of the automated token rotation job have allowed credentials to expire undetected.", "**How it''s identified:** Investigation consistently traces the failure to a bearer token or API credential that has exceeded its mandatory rotation window—either because the automated rotation job failed silently or because the credential aged past the configured expiry policy without a rotation attempt. Gateway logs reveal failed token refresh attempts and cascading authentication errors, while API call latency spikes dramatically as retries consume processing capacity."], "confidence": "high", "evidence": {"ticket_count": 18, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:53:30.991706+00:00"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/expired-api-token-auth-failures';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause of recurring HTTP 504 Gateway Timeout storms during batch sync jobs may be a stale, deprecated retry and backoff policy on the Integration Gateway that amplifies downstream latency into compounding retry storms.", "key_points": ["**Common pattern:** Affected users see repeated HTTP 504 errors during scheduled batch data synchronization jobs when downstream API latency spikes significantly beyond the gateway''s timeout window, with failure periods lasting 30 minutes or longer and delaying data availability for downstream consumers.", "**Scope / variation:** The issue may manifest as fully failed nightly batch sync jobs or as intermittent 504 responses in order fulfillment pipelines; gateway pod restarts do not resolve it, and temporarily extending the timeout threshold may reduce immediate failures but does not appear to eliminate the underlying retry amplification behavior.", "**How it''s identified:** Retry storms visible in distributed tracing during timeout windows — with logs showing only timeout-class errors rather than authentication or rate-limiting failures — appear consistent with a feedback loop where insufficiently bounded retries compound load on an already-slow downstream service, though this remains unverified."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:53:38.562119+00:00"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/stale-retry-backoff-amplifies-latency';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause of Integration Gateway 504 timeouts and sync failures during batch windows may be a stale expired API token cached on the gateway, potentially compounded by downstream API rate limiting or latency spikes.", "key_points": ["**Common pattern:** Scheduled integration jobs fail with HTTP 504 Gateway Timeout responses during overnight or early-morning sync windows, with queue backlogs climbing rapidly into thousands of unprocessed records; affected users typically notice missing or delayed data in downstream applications during daily reconciliation or on operations dashboards.", "**Scope / variation:** The interaction between authentication failure and throttling varies across incidents — in one case an expired cached token (beyond its 90-day TTL) and HTTP 429 rate-limit responses were both confirmed, while in another, credential failure could not be verified and downstream latency spikes appeared to be the dominant factor; trace sampling limitations may further restrict diagnostic coverage, leaving the root cause partially or fully inconclusive.", "**How it''s identified:** The issue may be recognisable by a combination of 504 timeout and, in some cases, 429 rate-limit responses on outbound Integration Gateway calls during scheduled batch windows, along with rapidly growing queue depth of pending records; however, confirming whether a stale cached token is involved requires reviewing token rotation history and gateway authentication logs, which have not always been available."], "confidence": "low", "evidence": {"ticket_count": 3, "root_cause_nature": "unconfirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:53:47.951225+00:00"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/unconfirmed-mixed-credential-latency-throttling';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, persistent sign-in failures after a password reset may be caused by an expired or invalid reset token that left credentials incompletely updated in directory services.", "key_points": ["**Common pattern:** Affected users complete a password reset through the Password Reset Portal that appears successful, but the new password is not accepted across the SSO portal and Microsoft 365 applications, and the Active Directory account becomes locked again shortly afterward — across multiple devices rather than a single endpoint.", "**Scope / variation:** Account lockouts may appear on a specific domain controller shortly after the reset attempt; cached or saved credentials on mobile devices might initially be suspected but appear to be ruled out as the locking source in reported cases."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:53:53.040792+00:00"}' WHERE family = 'ALP' AND root_cause_id = 'ALP/expired-reset-token-primary';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, recurring AD lockouts after a password reset may be caused by an unidentified service or legacy application still authenticating with stale cached credentials.", "key_points": ["**Common pattern:** Affected users experience repeated Active Directory lockouts every few minutes after a successful password reset, losing access to SSO Portal, Outlook, and OWA — even when desktop authentication works normally.", "**Scope / variation:** Mobile devices with cached credentials are a common suspected source, but in some cases lockouts persist after removing and re-adding corporate accounts on the device; the caller computer name field in lockout logs (Event ID 4740) may appear blank or reference a non-interactive caller, preventing definitive identification of the offending endpoint.", "**How it''s identified:** Lockout event logs may show regular-interval failed authentication attempts with ambiguous or missing caller information, which appears consistent with a background service or legacy client using outdated credentials — though the exact source often cannot be confirmed from available telemetry."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:53:59.627953+00:00"}' WHERE family = 'ALP' AND root_cause_id = 'ALP/stale-credentials-unidentified-source';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is stale cached credentials on iOS mobile devices continuing to submit the old password to Active Directory after a reset, triggering repeated account lockouts before the new password can be used.", "key_points": ["**Common pattern:** After a password reset, desktop sign-in works normally, but company iPhones running apps such as Outlook, Teams, Mail, or Safari keep retrying the old cached password in the background — often every 60 seconds — rapidly exceeding the AD lockout threshold and re-locking the account within minutes of each unlock.", "**Scope / variation:** The issue spans multiple departments, office locations, and network environments, including remote and traveling users. Lockout cycles can persist for hours across repeated unlock attempts. In some cases the lockout also blocks access to the Password Reset Portal and SSO Portal simultaneously, preventing self-service recovery and requiring service desk intervention. Saved passwords in the mobile browser and older mobile OS versions may also contribute.", "**How it''s identified:** Domain controller Event ID 4740 lockout entries trace repeated failed authentication attempts back to the mobile device''s IP address, confirming the lockout source is the iOS device rather than the desktop. The pattern of rapid, automated retries using outdated credentials — distinct from normal user sign-in failures — points to cached credentials on the mobile device as the root cause."], "confidence": "high", "evidence": {"ticket_count": 23, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:54:08.334161+00:00"}' WHERE family = 'ALP' AND root_cause_id = 'ALP/stale-mobile-cached-credentials';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is mobile devices continuing to submit stale cached credentials after a password change, triggering AD lockout, while the self-service password reset token expires before the user can complete recovery.", "key_points": ["**Common pattern:** Affected users experience repeated Active Directory account lockouts driven by corporate mobile devices (primarily iPhones, also managed Android) whose mail and collaboration apps—Outlook, Teams, native iOS Mail, Microsoft Authenticator—retry authentication in the background with outdated saved passwords, rapidly exceeding the lockout threshold. The self-service reset token then expires before the credential update can be completed, leaving users locked out of all SSO-connected resources with no self-service recovery path.", "**Scope / variation:** The issue presents differently across environments: desktop authentication may succeed while only mobile triggers the lockout; multiple apps on the same device can each independently retry stale credentials, accelerating failures; a previous device may continue submitting old credentials after a user migrates to a new phone; and domain controller replication lag can cause post-reset SSO failures even after a successful password change. Token time-to-live values range from fifteen minutes to over four hours, and in some cases the lockout recurs immediately after an admin unlock because cached credentials on the device have not yet been cleared."], "confidence": "high", "evidence": {"ticket_count": 33, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:54:16.041496+00:00"}' WHERE family = 'ALP' AND root_cause_id = 'ALP/stale-mobile-credentials-plus-expired-reset-token';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is an expired TLS certificate on the load balancer, resulting from a failed automated renewal process compounded by disabled certificate expiry alerting.", "key_points": ["**Common pattern:** Affected users and automated systems experience TLS handshake failures (e.g., \"NET::ERR_CERT_DATE_INVALID\") when connecting to internal web services over HTTPS; API calls, integration pipelines, health checks, and inventory sync processes fail TLS validation simultaneously.", "**Scope / variation:** In some cases the renewal job''s service account lost permissions after an RBAC policy change, producing an access-denied error; in others the renewal script exited with a non-zero code without triggering a notification or retry. Certificate expiry alerting had been explicitly disabled weeks or months prior, and dependent workflows such as DevOps pipelines and monitoring dashboards were also affected."], "confidence": "medium", "evidence": {"ticket_count": 3, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:54:22.389202+00:00"}' WHERE family = 'CES' AND root_cause_id = 'CES/automated-renewal-process-failed-to-complete';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is an expired TLS certificate on the load balancer: a renewed certificate and chain were issued but never successfully deployed to the load balancer''s TLS termination configuration, while disabled or misconfigured expiration monitoring prevented advance warning.", "key_points": ["**Common pattern:** Affected users see NET::ERR_CERT_DATE_INVALID browser warnings and TLS handshake failures across multiple offices simultaneously, with cascading 502/523/525 errors hitting CI/CD pipelines, API consumers, health checks, and business-critical applications such as payroll and inventory management.", "**Scope / variation:** The issue is not limited to a single deployment topology — variations include incomplete intermediate chain bundles, inconsistent deployment across multi-node load balancer clusters, incorrect chain ordering during import, stale certificates at both load balancer and backend layers, and Kubernetes ingress controllers referencing expired TLS secrets. The monitoring suppression mechanism also varies, from disabled alerting rules left over from maintenance windows to misconfigured thresholds or manual filters.", "**How it''s identified:** The load balancer is found still presenting an expired leaf certificate and outdated intermediate chain despite a renewed certificate having been issued by the internal CA; no corresponding configuration change exists on the load balancer, and pre-expiry alerting is confirmed to be inactive or suppressed."], "confidence": "high", "evidence": {"ticket_count": 46, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:54:31.196342+00:00"}' WHERE family = 'CES' AND root_cause_id = 'CES/renewed-chain-not-deployed-to-lb-with-monitoring-gap';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause may be a transient or path-specific certificate-serving fault on the F5 load balancer, though the root cause remains unverified.", "key_points": ["**Common pattern:** Affected users at a corporate office encountered TLS certificate date-invalid warnings in browsers and simultaneous TLS handshake failures on dependent internal API calls when accessing a service through an F5 load balancer.", "**Evidentiary gap:** Diagnostic review could not consistently reproduce an expired or defective certificate on the relevant F5 partition; the fault may have been transient or path-specific and might have cleared before validation was completed. A certificate-related fix was applied, after which the reported impact cleared, but this alone does not confirm the cause."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "unconfirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:54:36.827988+00:00"}' WHERE family = 'CES' AND root_cause_id = 'CES/unconfirmed-tls-presentation-issue-evidence-gap';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is an expired or incomplete TLS certificate chain on the load balancer, often compounded by certificate-monitoring alerts that failed to fire before expiration.", "key_points": ["**Common pattern:** Affected users and automated clients encounter TLS handshake failures (e.g., NET::ERR_CERT_DATE_INVALID) when accessing internal HTTPS services, with widespread impact across browser sessions and service accounts connecting through the same load balancer virtual server.", "**Scope / variation:** The issue is not limited to expired leaf certificates — in some cases the leaf certificate was valid but the load balancer served an expired or missing intermediate certificate. Remediation efforts were sometimes prolonged when the correct intermediate was absent from the deployment bundle, and misconfigured certificate-management monitoring rules prevented proactive detection in at least one instance."], "confidence": "medium", "evidence": {"ticket_count": 5, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:54:42.766246+00:00"}' WHERE family = 'CES' AND root_cause_id = 'CES/valid-leaf-but-stale-or-missing-intermediate-served';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause may be that a valid certificate belonging to a different internal service was bound to the F5 load balancer, resulting in hostname validation failures for all clients routed through the affected virtual IP.", "key_points": ["**Common pattern:** Internal users and automated services experience TLS handshake failures, browser certificate warnings, or SSL protocol errors when connecting to internal web and API endpoints through the load balancer — even though the bound certificate is valid and not expired.", "**Scope / variation:** The misconfiguration may go undetected because certificate monitoring checks only expiry rather than hostname or binding correctness, and some clients report a generic expired-certificate error instead of a hostname mismatch depending on their TLS library; additionally, the absence of a change record for the certificate binding during the renewal window could leave the issue invisible to change-management processes."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:54:48.296841+00:00"}' WHERE family = 'CES' AND root_cause_id = 'CES/wrong-certificate-bound-to-endpoint';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is BitLocker encryption being disabled, suspended, or incompletely attested on managed endpoints, causing Intune to evaluate devices as noncompliant and Conditional Access to block Microsoft 365 resources.", "key_points": ["**Common pattern:** Affected users on corporate-managed Windows 10/11 devices are blocked from SharePoint Online, Outlook, Exchange Online, or Dynamics 365 after a compliance policy requiring BitLocker encryption is enforced. Company Portal or the Intune admin console shows the devices as noncompliant.", "**Scope / variation:** The issue presents in several ways — encryption stalling during provisioning and requiring local user interaction, BitLocker protection found suspended rather than absent, or encryption never initiated until a forced policy sync. Stale device check-ins (over 24 hours) can compound the problem by delaying attestation reporting. Multiple devices across more than one office may be affected simultaneously following a policy rollout."], "confidence": "medium", "evidence": {"ticket_count": 3, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:54:57.003051+00:00"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/encryption-actually-disabled-or-attestation-failed';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a stale Intune check-in state after an OS update or compliance policy change, preventing the encryption signal from reaching the compliance service and triggering false Noncompliant status and Conditional Access blocks.", "key_points": ["**Common pattern:** Devices appear encrypted locally (BitLocker or device encryption confirmed via Control Panel or Company Portal), yet Intune marks them Noncompliant immediately after an OS update, upgrade, or encryption-policy change—blocking access to Microsoft 365 resources such as Outlook, Teams, and SharePoint Online. Forced syncs may briefly restore compliance, but the status reverts within minutes.", "**Scope / variation:** The issue has been observed on Windows 10, Windows 11, and Android 11 corporate-managed devices. It can be triggered by an admin-pushed compliance policy change (not only an OS update), and in some cases the device check-in timestamp in Intune is stale by over a week, preventing any compliance refresh until a manual sync is forced."], "confidence": "medium", "evidence": {"ticket_count": 4, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:55:02.972416+00:00"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/encryption-telemetry-broken-after-os-or-hardware-change';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause may be a stale Intune MDM check-in preventing compliance evaluation from refreshing, leaving Conditional Access to enforce an outdated noncompliant state.", "key_points": ["**Common pattern:** Affected devices appear noncompliant in Company Portal, triggering Conditional Access blocks to resources such as Outlook and OneDrive; manual sync attempts complete without error but do not update the compliance state.", "**Scope / variation:** The issue affected multiple users within a single group across Windows and Android platforms, with inconsistent behavior — some Android devices cleared noncompliance after a manual sync while most did not; Android cases surfaced an encryption-related policy condition, whereas Windows cases presented primarily as a stale check-in with no specific policy condition identified."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "unconfirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:55:08.777932+00:00"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/indeterminate-compliance-refresh-failure';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is a stale Intune check-in that leaves the device encryption signal missing or outdated, causing the Device Compliance Service to evaluate the device as noncompliant and Conditional Access to block access to Microsoft 365 and other protected resources.", "key_points": ["**Common pattern:** Affected users on corporate-managed devices are blocked from Microsoft 365 resources and other Conditional Access–protected services with errors such as \"Your device is not compliant.\" Company Portal shows a noncompliant status with a stale last-sync timestamp, and the encryption attribute appears blank, unknown, or \"Not Encrypted\" — even when local encryption (BitLocker, FileVault, or native encryption) is confirmed enabled on the endpoint.", "**Scope / variation:** The issue spans Windows 10/11, macOS, iOS/iPadOS, and Android devices, with stale check-in windows ranging from roughly 36 hours to over 14 days. On macOS, FileVault may not yet be fully enabled; on Windows, hardware changes (e.g., motherboard replacement) or BIOS updates can invalidate TPM attestation or pause BitLocker. A compliance policy update can trigger bulk noncompliance across an entire policy group, and a forced sync may briefly show compliant status in Intune while Conditional Access continues to block access until a full re-evaluation completes.", "**How it''s identified:** Device records in Intune show the encryption compliance attribute as missing, stale, or explicitly failing, paired with a last-sync timestamp well outside the expected check-in window — confirming that no current encryption signal has been reported to the Device Compliance Service."], "confidence": "high", "evidence": {"ticket_count": 27, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:55:17.808492+00:00"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/stale-checkin-missing-encryption-signal';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a stale BitLocker encryption compliance signal failing to propagate from Intune to Conditional Access, blocking Microsoft 365 access despite devices being actively encrypted and locally compliant.", "key_points": ["**Common pattern:** Affected users on Intune-managed Windows 10 or 11 laptops are denied access to Outlook, Teams, SharePoint, and other Microsoft 365 services, with Conditional Access citing a missing encryption signal even though BitLocker is verified as enabled locally and in the Intune or Company Portal. Manual syncs and reboots do not immediately resolve the block.", "**Scope / variation:** The issue appears across both Windows 10 and Windows 11 devices and is not tied to a specific OS version or network location. Some users see persistent blocks while others experience intermittent denials. In at least one case, the staleness extended to the Intune compliance record itself—not just the Conditional Access cache—showing noncompliant encryption despite a healthy local BitLocker state with a TPM key protector. Temporary Conditional Access exclusion groups have been used as a workaround while propagation completes."], "confidence": "medium", "evidence": {"ticket_count": 4, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:55:27.616476+00:00"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/stale-compliance-state-mismatch-ca-cache';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is deprecated Intune compliance policies remaining assigned to device groups after policy consolidation, causing devices to evaluate against retired policy revisions that lack current encryption signal mappings and triggering false Conditional Access blocks.", "key_points": ["**Common pattern:** Intune-managed Windows and Android devices are blocked from corporate resources (Exchange Online, SharePoint, Teams, Outlook, OneDrive) with encryption reported as \"EncryptionMissing\" or \"Not reported,\" even though BitLocker or device-level encryption is confirmed enabled. The issue typically surfaces after compliance policy consolidation or baseline refresh activities.", "**Scope / variation:** The issue affects Windows 10, Windows 11, and Android devices across multiple offices and security groups. Remote or traveling users may experience prolonged noncompliance due to extended check-in gaps. In at least one case, the missing encryption signal reflected a genuine device state (stalled BitLocker after an OS update), and some devices faced secondary blockers such as pending cumulative updates even after the policy reference was corrected. Mobile device access via personal phones generally remained unaffected."], "confidence": "medium", "evidence": {"ticket_count": 7, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:55:35.913263+00:00"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/stale-deprecated-compliance-policy-reference';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is a missing, outdated, or incorrectly configured conditional forwarder on the affected internal DNS resolver, leading to intermittent NXDOMAIN, SERVFAIL, or timeout responses for internal hostnames while other resolvers or direct IP access work normally.", "key_points": ["**Common pattern:** Affected users see intermittent DNS resolution failures (NXDOMAIN, SERVFAIL, or timeouts) for internal hostnames on specific corporate resolvers, while the same records resolve correctly against authoritative servers, from other subnets, or via direct IP access — often initially mistaken for application outages.", "**Scope / variation:** Impact ranges from partial failure (e.g., 20–30% of queries failing when the resolver round-robins between valid and decommissioned forwarder targets) to broad outages spanning multiple zones or geographically dispersed offices sharing the same misconfigured resolver. The issue may surface after scheduled DNS maintenance, and a cache flush alone will not resolve it if the underlying forwarder entry remains incorrect.", "**How it''s identified:** The resolver-specific and subnet-specific nature of the failure is the key signal: comparing query results across resolvers reveals that affected resolvers return negative or stale responses while others return correct answers, pointing to a forwarder misconfiguration rather than an authoritative zone or network issue."], "confidence": "high", "evidence": {"ticket_count": 13, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:55:44.811447+00:00"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/missing-or-incorrect-conditional-forwarder';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, intermittent DNS resolution failures for internal hostnames may be caused by client-side DNS cache staleness or local network/resolver configuration issues rather than a central DNS infrastructure fault.", "key_points": ["**Common pattern:** Affected users experience NXDOMAIN responses or resolution to outdated IP addresses for internal hostnames, while other systems on the same network resolve the same names correctly; the issue is most visible after network changes or long-running sessions and may clear after flushing the local DNS cache or reconnecting to VPN.", "**Scope / variation:** In one case, an endpoint returned a stale cached IP belonging to a decommissioned host; in another, reconnecting to the corporate VPN was required to restore resolution, suggesting a network transition may have left the client with an unusable or outdated resolver configuration."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "unconfirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:55:50.453252+00:00"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/no-server-side-fault-client-side-or-transient';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is stale or inconsistent data in caching/forwarding resolvers after DNS maintenance or zone migrations, producing mixed NXDOMAIN, SERVFAIL, timeout, and stale-record responses for internal hostnames.", "key_points": ["**Common pattern:** Affected users see intermittent failures resolving internal hostnames — a mix of NXDOMAIN, SERVFAIL, timeouts, and stale A records — preventing connectivity to databases, backend services, and internal tools. Failures appear non-uniformly across subnets, resolver paths, and office locations, with symptom onset correlating to recent DNS maintenance windows or zone migrations.", "**Scope / variation:** The issue varies by resolver instance: some hosts receive stale records pointing to outdated IPs after an endpoint migration, others see roughly 40% NXDOMAIN on a per-query basis, and at least one resolver intermittently returned SERVFAIL even after a cache flush. In some cases, missing change-log evidence due to log rotation prevented full confirmation of the root cause on the authoritative side."], "confidence": "medium", "evidence": {"ticket_count": 3, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:55:57.520899+00:00"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/resolver-path-inconsistency-mixed-cause';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is a stale A record persisting in the internal authoritative DNS zone after a service migration or host decommissioning, compounded by recursive resolvers serving outdated cached data due to high TTL values or unflushed caches.", "key_points": ["**Common pattern:** Affected users and internal services see intermittent DNS resolution failures — queries for internal hostnames return an outdated IP address or NXDOMAIN inconsistently across subnets and locations, causing connection timeouts, health-check failures, broken deployment pipelines, and degraded dashboards.", "**Scope / variation:** The issue can manifest differently across environments: some resolvers serve purely NXDOMAIN while others return the correct address; some clients see SERVFAIL or query timeouts instead of NXDOMAIN; in some cases the authoritative zone is already correct but a deprecated policy reference in the resolver configuration keeps stale data in play, and multiple hostnames within the same zone may be affected simultaneously."], "confidence": "high", "evidence": {"ticket_count": 14, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:56:04.585479+00:00"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/stale-authoritative-zone-record';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is stale cached A records on internal recursive resolvers that were not refreshed after an authoritative zone update, with high TTL values prolonging the delivery of outdated or negative-cached responses.", "key_points": ["**Common pattern:** After an internal DNS zone change, affected users and services see intermittent name-resolution failures — a mix of outdated A records, NXDOMAIN, SERVFAIL, and timeouts — even though authoritative servers already reflect the correct entry. Results vary by resolver, with some returning correct data while others serve stale cached records.", "**Scope / variation:** The issue can span multiple office locations and datacenter segments sharing overlapping resolver infrastructure. Downstream caching forwarders may continue serving stale data even after the primary resolver cache is cleared, and some resolvers require a full service restart rather than a simple cache flush. Records with very high TTLs (e.g., 86400 seconds) tied to decommissioned hosts are especially prone to prolonged staleness. Impact extends to CI/CD pipelines, health checks, monitoring systems, and service-to-service communication."], "confidence": "high", "evidence": {"ticket_count": 23, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:56:11.038070+00:00"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/stale-resolver-cache-after-record-change';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is that BitLocker was never fully initialized on affected endpoints — possibly due to missing or unapplied Intune policy or unverified TPM readiness — leaving no recovery key escrowed and devices flagged as noncompliant.", "key_points": ["**Common pattern:** Corporate-managed Windows 10 laptops appear as noncompliant for disk encryption in Intune, with no BitLocker recovery key visible in Azure AD or tenant escrow. In at least one case, a user accepted the BitLocker enablement prompt but encryption never progressed.", "**Scope / variation:** Reported across a small number of devices; circumstances vary — one case involved a user who confirmed accepting the prompt weeks earlier with no progress, another was filed by a third party, and another was tied to a specific business group''s enrollment context (Finance)."], "confidence": "medium", "evidence": {"ticket_count": 3, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:56:17.078579+00:00"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/inconclusive-evidence-bitlocker-not-fully-enabled';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a deprecated or stale Intune Endpoint Encryption Policy remaining assigned to affected devices, preventing the current active policy from applying and blocking BitLocker activation and recovery key escrow.", "key_points": ["**Common pattern:** Affected devices show as noncompliant for encryption in Company Portal and Intune dashboards after enrollment, BitLocker does not activate, and no recovery key is visible in the management portal. TPM state varies — some devices have an uninitialized TPM, others have the TPM protector present but protection still off.", "**Scope / variation:** The issue spans multiple offices and user groups, though peer devices in the same assigned groups are typically unaffected. Notable exceptions include a device inadvertently excluded from its intended device group (receiving no policy at all), a device with conflicting telemetry showing a recovery key escrowed despite noncompliance status, and a device that had not completed an MDM sync since before the latest policy rollout."], "confidence": "medium", "evidence": {"ticket_count": 6, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:56:23.427056+00:00"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/intune-policy-not-assigned-or-stale-deprecated-policy';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a desynchronization between local BitLocker encryption status and Intune compliance reporting, stemming from backend reporting mismatches, incomplete TPM protector bindings, or MDM sync errors blocking recovery key escrow.", "key_points": ["**Common pattern:** Affected users have managed Windows 10 laptops where BitLocker is confirmed fully enabled on the OS volume locally, yet Intune displays an \"EncryptionNotEnabled\" noncompliant status and recovery keys are absent from Azure AD or Intune escrow, leaving devices in a blocked compliance state.", "**Scope / variation:** Three distinct root causes have been observed: a backend compliance reporting desync where Azure AD confirmed escrow but Intune still reported \"NotEncrypted\"; an incomplete protector configuration with only a Numerical Password protector and no TPM binding (seen on a Surface Laptop 4); and an MDM sync error (0x80180014) across consecutive check-ins that prevented recovery key escrow entirely. In one case, the Company Portal app explicitly showed a \"last sync failed\" status."], "confidence": "medium", "evidence": {"ticket_count": 3, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:56:31.208836+00:00"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/mdm-sync-failure-causing-state-desync';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a failed or incomplete BitLocker recovery key escrow to Azure AD/Intune, leaving devices noncompliant for encryption despite a healthy TPM and correct policy assignment.", "key_points": ["**Common pattern:** Intune-managed Windows 10 devices show persistent encryption noncompliance in Company Portal or the Device Compliance Service, even though TPM 2.0 is functional and a BitLocker policy is correctly assigned. The recovery key is absent from the cloud device record, and manual sync attempts do not resolve the status.", "**Scope / variation:** The escrow failure surfaces in multiple forms — error codes such as 0x87D1FDE8 (KeyBackupError), 0x80090010, or 0x80070005 (access denied) may appear in MDM or BitLocker event logs. In some cases BitLocker protection is suspended rather than disabled; in others, encryption was never initiated despite policy assignment. An escrow upload timeout (BitLocker-API Event ID 846) can also cause a timing mismatch between local encryption state and cloud compliance status. The issue has been observed across different business groups and locations."], "confidence": "medium", "evidence": {"ticket_count": 7, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:56:38.173913+00:00"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/recovery-key-escrow-failure-despite-healthy-tpm-and-policy';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is an uninitialized TPM protector on the endpoint, which prevents BitLocker from creating key protectors, starting encryption, and escrowing a recovery key to Azure AD — leaving the device noncompliant in Intune.", "key_points": ["**Common pattern:** Affected devices are flagged as noncompliant for disk encryption in Intune or Company Portal, BitLocker shows \"Protection Off\" with no key protectors configured, and no recovery key appears in Azure AD. Users never received a BitLocker PIN prompt or encryption setup during provisioning, and access to compliance-gated resources (VPN, email, SharePoint) is blocked.", "**Scope / variation:** The issue occurs after reimaging without a TPM initialization step, motherboard replacements that invalidate a prior protector, or Autopilot provisioning flows where TPM initialization was skipped. In some cases the device also lacks the required Azure AD security group membership or Intune policy assignment after re-enrollment. Even after remediation, recovery key escrow may fail intermittently with timeout or \"KeyPackage not found\" errors, and MDM sync errors (e.g., 0x80180014 or 0x80180026) may accompany the escrow failure."], "confidence": "high", "evidence": {"ticket_count": 32, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:56:45.135337+00:00"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/tpm-protector-not-initialized';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is a backlog of endpoint protection scans triggering simultaneously at user login, compounded by multiple resource-heavy startup items and low free disk space on the system drive.", "key_points": ["**Common pattern:** Affected users on managed Windows 10 laptops see sustained 80–100% CPU usage immediately after sign-in, with MsMpEng.exe (or a comparable endpoint protection process) dominating Task Manager. Core applications such as Outlook, Teams, and browsers take 10 seconds to over five minutes to open, fans run continuously, and the slowdown persists across reboots.", "**Scope / variation:** The issue spans both Microsoft Defender and CrowdStrike Falcon environments, with scan backlogs ranging from a handful of deferred jobs to over 14,000 queued entries. Free disk space on affected 256 GB drives ranged from roughly 2 GB to 19 GB, and some devices had up to 14 concurrent startup items. Inconsistent policy deployment meant identically configured laptop models could be affected or unaffected depending on whether corrected scheduling policies had been applied.", "**How it''s identified:** The endpoint protection process is the top CPU consumer at login, and inspection of the scan queue reveals a backlog of deferred or missed scans that accumulated after a policy refresh or extended offline period. Low system-drive free space and a high number of concurrent startup items are consistent aggravating factors; once the backlog is cleared and policies corrected, CPU usage returns to normal within minutes."], "confidence": "high", "evidence": {"ticket_count": 53, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:56:53.260003+00:00"}' WHERE family = 'LPD' AND root_cause_id = 'LPD/endpoint-scan-backlog-startup-disk-contention';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, post-login sluggishness on managed Windows 10 laptops may be linked to temporary file accumulation exhausting system drive space, causing broad disk contention.", "key_points": ["**Common pattern:** Affected users experience general slowness across Outlook, Chrome, File Explorer, and other applications in the minutes after login, with no single app failing — rather, desktop responsiveness is broadly degraded.", "**Scope / variation:** Users may initially attribute the onset to a recent company update push, but in reported cases the issue appears consistent with disk-space exhaustion from temp-file buildup rather than an update- or policy-related change. The diffuse nature of the slowdown can make it difficult for affected users to identify the source."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:56:59.060445+00:00"}' WHERE family = 'LPD' AND root_cause_id = 'LPD/low-disk-temp-file-accumulation';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause of severe post-login slowness on managed Windows 10 laptops is a recently pushed corporate startup policy that launches multiple resource-heavy processes simultaneously, driving CPU to 70–90% and delaying application responsiveness.", "key_points": ["**Common pattern:** Affected users experience significant slowness within one to two minutes of signing in — CPU usage spikes to 70–90%, and applications like Outlook, Teams, Chrome, and Explorer take 20–60 seconds to open. Performance gradually improves after several minutes but may remain degraded throughout the session.", "**Scope / variation:** The issue has appeared across multiple office locations and groups (e.g., Sales, Mobile Workforce) and has been delivered via both Group Policy (GPO) and Intune, with identical symptoms. In some cases a single enforced startup application (such as an asset inventory agent) is the dominant CPU consumer rather than a combination of processes. At least one case was initially misattributed to a different root cause before the startup policy was confirmed as the trigger.", "**How it''s identified:** Diagnostic review of affected endpoints shows multiple resource-intensive processes — endpoint management extensions, policy-enforcement tasks, inventory agents, sync triggers, and telemetry collectors — all launching simultaneously at login, with the onset aligning directly to the timing of a corporate startup policy push."], "confidence": "medium", "evidence": {"ticket_count": 3, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:57:06.657340+00:00"}' WHERE family = 'LPD' AND root_cause_id = 'LPD/resource-heavy-startup-policy';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause of intermittent post-login slowdown may be transient high CPU usage by the Windows Defender antimalware service (MsMpEng.exe) during startup scanning, though this remains unverified.", "key_points": ["**Common pattern:** Affected users experience 20–30 second delays opening Outlook, a web browser, and File Explorer immediately after sign-in on a corporate Windows 10 laptop, most frequently in the morning after the device has been powered off overnight; Task Manager shows MsMpEng.exe consuming approximately 95% of CPU during these episodes.", "**Reproducibility:** The slowdown is intermittent and could not be reproduced during a live support session; disabling user-configured startup items did not resolve the issue, and no confirmed root cause has been established."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "unconfirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:57:12.066234+00:00"}' WHERE family = 'LPD' AND root_cause_id = 'LPD/unconfirmed-transient-post-login-slowdown';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is Exchange Online backend throttling (HTTP 429 / EWS throttling responses) disrupting ActiveSync and Outlook client synchronization, while a stale desktop profile and OST file compound desktop-side symptoms.", "key_points": ["**Common pattern:** Outlook desktop shows \"Disconnected\" and mobile clients report sync errors or \"last synced: never,\" yet Outlook on the Web continues working normally. The disruption often starts in the morning and persists through standard troubleshooting such as app restarts and device reboots.", "**Scope / variation:** The issue can present as a split-client experience — rebuilding the desktop Outlook profile may restore desktop sync while the mobile client remains broken. MDM device non-compliance holds may compound mobile failures, and transient recovery after ActiveSync re-pairing often relapses. Error code 0x800CCC0E has been observed alongside HTTP 429 throttling responses on mobile clients.", "**How it''s identified:** Exchange Online diagnostics reveal HTTP 429 throttling responses or EWS throttling entries against affected mailboxes during sync attempts; recovery has been achieved after a temporary throttle exception was applied at the service level, confirming backend throttling as the primary factor."], "confidence": "medium", "evidence": {"ticket_count": 3, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:57:19.233002+00:00"}' WHERE family = 'OES' AND root_cause_id = 'OES/exchange-online-mailbox-throttling';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, intermittent Outlook sync failures across desktop and mobile platforms may be caused by corrupted Microsoft 365 authentication tokens preventing stable reauthentication.", "key_points": ["**Common pattern:** Affected users experience intermittent \"Disconnected\" status in Outlook Desktop on Windows 10 alongside repeated sign-in prompts, with messages failing to arrive; managed iOS devices may simultaneously report a \"sync failed\" error.", "**Scope / variation:** The issue may present differently across platforms — desktop clients show intermittent connectivity loss rather than full disconnection, while mobile clients display an explicit sync error. Notably, rebuilding the Outlook profile does not resolve the failure, distinguishing it from a stale-profile scenario.", "**How it''s identified:** The issue appears consistent with an authentication token problem when sync failures persist across both desktop and mobile platforms despite a healthy Exchange Online connection and normal mobile device partnership, and when a profile rebuild fails to restore normal operation."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:57:26.505649+00:00"}' WHERE family = 'OES' AND root_cause_id = 'OES/expired-m365-auth-tokens';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is an Intune device compliance policy change marking managed mobile devices as non-compliant, prompting Exchange Online to block ActiveSync and mobile API access for those endpoints.", "key_points": ["**Common pattern:** Affected users lose email sync on iOS or Android Outlook Mobile — seeing a \"Disconnected\" banner, \"Last synced: never,\" or silently missing new mail and push notifications — while Outlook on the web and desktop Outlook typically continue working normally.", "**Scope / variation:** The issue can affect individual users or entire groups simultaneously after a single compliance policy push, spanning multiple offices and device platforms; in some cases Outlook Mobile may still show \"Connected\" despite no mail arriving, and stale desktop Outlook profiles or EWS HTTP 429 throttling from aggressive retry loops can add secondary disruption. Triggers range from a new policy requirement or deprecated policy reference to a missing OS security patch or a re-enrollment compliance gap.", "**How it''s identified:** The affected device is marked non-compliant in Intune MDM — often correlating with a recent compliance policy update or evaluation timestamp — and Exchange Online transport logs show HTTP 403 rejections for the mobile sync partnership, confirming the compliance block rather than a mailbox or network issue."], "confidence": "high", "evidence": {"ticket_count": 16, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:57:35.482627+00:00"}' WHERE family = 'OES' AND root_cause_id = 'OES/intune-mdm-device-compliance-block';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is stale or corrupted Outlook desktop profiles—typically triggered by Office updates, weekend patch cycles, or profile rollouts—that invalidate cached mailbox settings and OST files, blocking MAPI-over-HTTP sync with Exchange Online.", "key_points": ["**Common pattern:** Affected users see a persistent \"Disconnected\" status in Outlook Desktop that survives restarts, sign-out/sign-in, and manual Send/Receive, while Outlook on the web continues working normally for the same mailbox.", "**Scope / variation:** The issue can appear as isolated single-user incidents or affect entire teams simultaneously after a patch cycle; in some cases mobile devices also stop syncing due to stale sync partnerships or Intune noncompliance flags, even after the desktop profile is rebuilt, requiring separate remediation.", "**How it''s identified:** Autodiscover traces on affected workstations may reveal authentication failures (HTTP 401) tied to a stale profile GUID, and OST file inconsistencies are found on impacted machines, while Exchange Online service health remains healthy and Outlook on the web confirms normal mailbox access."], "confidence": "high", "evidence": {"ticket_count": 11, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:57:42.627901+00:00"}' WHERE family = 'OES' AND root_cause_id = 'OES/stale-corrupted-outlook-desktop-profile-cache';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a stale ActiveSync device partnership or invalid mobile profile that prevents Outlook mobile from re-establishing sync with Exchange Online after a device or policy change.", "key_points": ["**Common pattern:** Outlook mobile shows a persistent \"Disconnected\" status and the inbox appears frozen with no new messages, while desktop Outlook and Outlook on the web continue working normally for the same mailbox. Restarting or reinstalling the app typically does not help, and no explicit error code is displayed.", "**Scope / variation:** The issue affects both iOS and Android devices and has been observed following iOS version updates, Intune compliance policy transitions, and prior desktop Outlook profile rebuilds. In some cases both mobile and desktop clients were affected simultaneously; in others, only the mobile path was impacted. Resolution has varied — some cases required server-side ActiveSync partnership clearance, while at least one resolved with a client-side account removal and re-add alone.", "**How it''s identified:** The mobile device partnership entries in Exchange Online show stale last-sync timestamps, and sync logs may reveal repeated HTTP 401 authentication errors, all while the device reports as compliant in Intune and other mail clients function normally."], "confidence": "medium", "evidence": {"ticket_count": 9, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:57:50.838610+00:00"}' WHERE family = 'OES' AND root_cause_id = 'OES/stale-mobile-sync-partnership';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause may be a transient Exchange Online service-side mailbox sync fault, as the failure spans multiple clients for a single mailbox while other users remain unaffected.", "key_points": ["**Common pattern:** Affected users see sync failures across both desktop and mobile Outlook clients simultaneously — desktop shows a persistent or flickering Disconnected status while mobile displays stale data with no new messages arriving, and standard remediation (profile rebuilds, app restarts, airplane mode) does not fully resolve the issue.", "**Scope / variation:** Presentation may vary: in some cases the desktop connection status flickers intermittently rather than staying steadily disconnected, and a desktop profile rebuild might partially restore sync on that platform alone while mobile remains broken. The issue appears isolated to a single mailbox rather than affecting the tenant or network broadly.", "**How it''s identified:** The distinguishing signal is that the same mailbox fails to sync on multiple independent clients and platforms at the same time, with no MDM compliance issues, no reported Microsoft 365 service outage, and no impact on other users — pointing away from client-side, device-specific, or network causes and toward a possible mailbox-level service condition that has not yet been confirmed."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:57:59.773149+00:00"}' WHERE family = 'OES' AND root_cause_id = 'OES/suspected-server-side-mailbox-fault';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a corrupted Outlook desktop profile combined with an unhealthy mobile sync partnership and a stale MDM legacy-block rule that incorrectly targets current devices after tenant maintenance.", "key_points": ["**Common pattern:** Affected users — primarily in Sales, Field Ops, and Corporate Sales — find both Outlook desktop and Outlook mobile stop syncing simultaneously, with the desktop client showing \"Disconnected\" status and mobile devices ceasing to receive new mail, while OWA continues to work normally.", "**Scope / variation:** Onset may follow a weekend maintenance window or appear mid-week; Intune may or may not flag the mobile device as non-compliant; Exchange Online logs can show intermittent successful sync activity, creating a mixed-state condition rather than a complete outage. An outdated MDM legacy-block policy originally scoped for decommissioned iOS devices has been found matching current devices post-maintenance in at least one instance."], "confidence": "medium", "evidence": {"ticket_count": 7, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:58:05.422551+00:00"}' WHERE family = 'OES' AND root_cause_id = 'OES/unresolved-endpoint-client-sync-state';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is a corrupt or checksum-mismatched printer driver package on the print server, typically introduced during an automated driver deployment, which prevents the Print Spooler from loading drivers for shared queues and blocks all job processing.", "key_points": ["**Common pattern:** Print jobs remain stuck at zero percent or accumulate indefinitely in server-hosted queues, shared printers show \"driver unavailable\" or appear offline on client workstations, and client-side actions such as rebooting or re-adding printers have no effect. The Print Spooler logs repeated driver load failures (Event ID 372) and restarting the spooler provides only brief relief before jobs stall again.", "**Scope / variation:** The issue may affect a single queue or multiple queues sharing the same driver package across departments on the same server. Corruption sources vary — partial driver updates leaving mixed old and new files, unsigned packages, Windows cumulative updates, or Group Policy–driven driver distribution. In some cases the spooler enters a crash loop (Event ID 7031) rather than running in a degraded state, and driver DLL files may be entirely absent from the spool directory rather than merely corrupted.", "**How it''s identified:** Checksum or hash verification of the installed driver package against the approved repository copy reveals a mismatch or corruption, and server-side event logs show recurring driver load failure codes (0x00000709, 2147500037, ERROR_PRINTER_DRIVER_CORRUPT) correlated with a recent automated deployment or maintenance window. Local USB-attached printing remains unaffected, confirming the fault is isolated to the server-side driver layer."], "confidence": "high", "evidence": {"ticket_count": 48, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:58:16.885790+00:00"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/corrupt-driver-package-spooler-load-failure';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause of shared print queues stalling after a maintenance window may be that an administrative action left the queues in a paused state that was not immediately visible.", "key_points": ["**Common pattern:** Print jobs submitted to shared queues on a print server remain indefinitely in a spooling state after a maintenance window, affecting multiple department-specific queues on the same server. The queues may appear superficially unhealthy rather than explicitly paused, leading initial troubleshooting toward driver or spooler issues.", "**Scope / variation:** Some affected users may see a \"Driver unavailable\" message, which could be a secondary symptom rather than the actual fault. Restarting the print spooler service might provide only brief, temporary relief before the issue recurs."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:58:22.517973+00:00"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/queue-left-paused';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause of print jobs stalling in a shared queue may be incorrect ACL permissions on the print server''s queue or spool directory, preventing the spooler service account from processing jobs.", "key_points": ["**Common pattern:** Jobs submit to the shared printer queue but never complete; affected users may see access-related errors, offline printer status, driver-unavailable messages, or spooler timeouts, while the printer remains visible and workstation connectivity appears intact.", "**Scope / variation:** The issue may present differently across workstations — some users receive explicit access errors while others see the printer as offline or encounter timeout messages; it can span multiple floors or network segments, pointing to a server-side rather than workstation-side problem.", "**How it''s identified:** An EventID 7011 access error during spooler processing, combined with ruling out paused queues and driver faults, appears consistent with a permissions issue on the print queue or spool path rather than a connectivity or driver problem."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:58:31.224246+00:00"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/spool-directory-permissions';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause of print jobs stuck indefinitely in shared queues is a stale or corrupt queue-to-driver mapping on the print server, typically left behind after a partial driver reinstall or scheduled update.", "key_points": ["**Common pattern:** Affected users see \"Driver unavailable\" or \"printer offline\" status on shared print queues, with jobs stuck at 0% across multiple users; workstation reboots and job retries have no effect because the issue resides on the centralized print server.", "**Scope / variation:** The issue appears across multiple device types (workstations and laptops) connecting to the same shared queue, and may involve legacy driver variants (e.g., PCL5 mapped instead of approved PCL6), CRC/checksum validation failures, or repeated Event ID 372 entries on the print server. Spooler restarts typically provide only temporary relief, with stuck jobs recurring within approximately 24 hours, and incomplete remediation has led to repeat incidents."], "confidence": "medium", "evidence": {"ticket_count": 6, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:58:37.775977+00:00"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/stale-queue-driver-mapping';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, intermittent stalling of complex print jobs on a shared printer may be related to a document rendering or printer-side processing issue that could not be fully isolated.", "key_points": ["**Common pattern:** Print jobs stall at zero percent progress on the print server, with a \"Driver unavailable\" status on the server and an \"offline\" status on workstations; simple test pages print successfully, but larger or multi-page documents hang indefinitely or experience significant delays.", "**Scope / variation:** The issue appears across at least three floors and multiple departments, suggesting it is not limited to a single network segment; the status message displayed may differ between the server side and individual workstations.", "**How it''s identified:** Standard queue and driver diagnostics did not reveal a consistent failure, and the behavior was only partially reproducible; the distinguishing signal is that simple jobs succeed while complex documents consistently stall, pointing to a possible rendering or printer-side processing issue that may require vendor escalation to confirm."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:58:45.558092+00:00"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/unresolved-rendering-escalation-holding';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is broken NTFS inheritance or an explicit deny ACE on the Finance shared folder, overriding valid AD group permissions and producing \"Access is denied\" (0x80070005) errors that persist across client-side remediation.", "key_points": ["**Common pattern:** Affected users receive a credential prompt followed by \"Access is denied\" when opening the Finance shared drive on Windows 10, despite confirmed AD security group membership. Standard client-side steps — clearing cached SMB credentials, remapping the drive, or switching workstations — do not resolve the issue, pointing to a server-side cause.", "**Scope / variation:** The error may appear only when navigating into a specific subfolder rather than at the share level. In some instances file server logs show intermittent rather than consistent denials, and colleagues on the same team remain unaffected because their accounts belong to a legacy security group that is still listed on the folder ACL, making the issue appear account-specific.", "**How it''s identified:** NTFS ACL review on the file server reveals that the expected security group is missing from the folder ACL due to broken inheritance, or that an explicit deny ACE on a parent or target folder overrides the group-based allow permissions. File server access logs corroborate the denial by recording NT_STATUS_ACCESS_DENIED events for the affected users'' SIDs even after group membership is verified."], "confidence": "medium", "evidence": {"ticket_count": 5, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:58:53.443224+00:00"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/broken-ntfs-acl-inheritance-or-deny-ace';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is the affected user''s Active Directory account missing membership in the department-level security group required by the shared drive''s share and NTFS ACLs, leaving the group SID absent from the Kerberos token and resulting in access denial despite valid credentials.", "key_points": ["**Common pattern:** Affected users receive \"Access is denied\" (0x80070005) when opening departmental shared drives via mapped drive letters or UNC paths, while colleagues in the same department access the same share without issue. Credential prompts may loop repeatedly, and standard remediation such as signing out, clearing cached credentials, or remapping the drive does not resolve the problem.", "**Scope / variation:** The issue spans multiple departments (Finance, HR, Engineering, and others) and arises from several root circumstances — incomplete onboarding or transfer provisioning, automated AD group cleanup or sync scripts that inadvertently removed the membership, or access requests not yet fulfilled. In some cases denial occurs only at a specific subfolder rather than the share root, and separate broken-ACL-inheritance issues on subfolders have been found coincidentally during investigation.", "**How it''s identified:** Reviewing the affected user''s Active Directory group memberships reveals the account is not a member of the security group referenced in the share and NTFS ACLs, confirming a server-side entitlement gap rather than a credential or network issue."], "confidence": "high", "evidence": {"ticket_count": 23, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:59:01.532659+00:00"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/missing-ad-security-group-membership';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is a compound condition where the affected user''s AD account is missing the required security group for the departmental share, compounded by stale cached credentials or an unrefreshed Kerberos token on the workstation that triggers repeated credential prompts and persistent access denial.", "key_points": ["**Common pattern:** Affected users on domain-joined Windows 10 workstations receive repeated credential prompts followed by \"Access is denied\" (0x80070005 / NT_STATUS_ACCESS_DENIED) when accessing departmental shared drives via mapped drives or UNC paths, while teammates with valid group membership connect normally.", "**Scope / variation:** The issue most commonly follows a password reset, AD group cleanup, or maintenance window. Variations include access requests not yet propagated to the logon token, broken NTFS inheritance or explicit deny entries persisting after group correction, legacy individual-SID ACL conflicts from prior migrations, stale GPO drive-mapping references, and cases where the user appears in a distribution list but not the security group referenced by the share ACL."], "confidence": "high", "evidence": {"ticket_count": 17, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:59:07.367874+00:00"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/missing-group-plus-stale-credential-or-acl-compound';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, repeated credential prompts and \"Access is denied\" errors on mapped SMB drives may be caused by stale cached credentials in Windows Credential Manager that no longer reflect a recent password or AD group membership change.", "key_points": ["**Common pattern:** Affected users on domain-joined Windows 10 workstations encounter repeated credential prompts followed by \"Access is denied\" (sometimes Error 5) when opening department shared folders via mapped drives, even after re-entering valid credentials.", "**Scope / variation:** The issue has appeared in at least two contexts — after a same-day password change and after an AD group membership update processed days prior — and may reproduce when navigating directly via UNC path as well as mapped drives. Historical NTFS deny entries were noted on the file server but do not appear to be the immediate cause, as access was restored without ACL changes."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:59:13.411566+00:00"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/stale-cached-smb-credentials';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause may be a mapped drive still targeting a retired UNC path from a previous file server migration, with stale cached credentials blocking access even to the correct server.", "key_points": ["**Common pattern:** Affected users see \"Access Denied\" (0x5) errors on a mapped network drive, with intermittent credential prompts that persist even after entering valid domain credentials; the issue is isolated to the individual workstation while colleagues in the same security group retain normal access.", "**Scope / variation:** The mapped drive letter may silently reference a retired UNC path from a prior file server migration, and stale cached credentials associated with the old path could also cause failures when navigating directly to the correct current UNC path."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:59:18.815658+00:00"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/stale-or-wrong-mapped-share-path';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause of \"Access is denied\" errors and repeated credential prompts on a departmental share may be a discrepancy between confirmed AD group membership and the Kerberos token actually presented during authentication.", "key_points": ["**Common pattern:** Affected users receive \"Access is denied\" errors and repeated credential prompts when accessing a departmental shared drive via mapped drive or UNC path; the issue is account-specific, with colleagues holding equivalent access unaffected.", "**Possible cause:** AD group membership appears correct, but the Kerberos token on the affected workstation may not consistently reflect that membership — one possible explanation is a backend permission replication or authentication-layer issue, though this remains unverified and requires higher-tier review."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "unconfirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:59:23.551043+00:00"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/unconfirmed-backend-replication-or-auth-escalated';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is an endpoint protection application control policy blocking the installer because its hash, publisher signature, or approval entry is missing from the approved-applications allowlist.", "key_points": ["**Common pattern:** Affected users see errors such as \"Installation blocked by policy\" or codes like 0x80070005, 0x87D00324, or EP-4031 when deploying software through Software Center, despite healthy device enrollment, Intune compliance, and correct entitlement group membership.", "**Scope / variation:** The issue spans multiple offices, departments, and application types (VPN clients, productivity suites, LOB tools, finance apps). The block may cite an unapproved publisher signature, a specific policy name (e.g., \"BlockUnsignedInstallers\"), or an installer hash mismatch; the affected application may vanish from the Software Center catalog after a failed attempt or appear intermittently. Manual pushes by local IT are also blocked, confirming it is not limited to self-service workflows.", "**How it''s identified:** Endpoint protection logs on the affected device show a quarantine or deny action triggered by an application control rule against the installer package, confirming the block originates from the allowlist policy rather than from enrollment, compliance, or targeting issues."], "confidence": "medium", "evidence": {"ticket_count": 7, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:59:31.228060+00:00"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/endpoint-protection-app-control-block';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is Endpoint Protection or Defender Application Control blocking approved installers due to missing allowlist approvals, combined with stale Intune inventory preventing updated security policies and application assignments from reaching the device.", "key_points": ["**Common pattern:** Affected users on managed Windows endpoints see approved applications missing from Software Center or failing immediately with errors such as \"Installation blocked by Endpoint Protection,\" \"PolicyCheckFailed:EP-403,\" or codes like 0x80070005 and 0x87D13B3. Investigation reveals both an active Endpoint Protection block (hash mismatch, missing signature approval, or heuristic detection) and a stale Intune device sync, typically 36 hours to ~30 days behind.", "**Scope / variation:** The issue spans multiple departments, offices, and application titles. Presentations vary: the app may be entirely absent from the catalog, visible but failing instantly on install, or appearing intermittently or only under an administrative account. It can recur after a prior fix when a new installer version introduces an updated hash not yet allowlisted, and may affect multiple users in the same device group simultaneously—including recently re-enrolled or hardware-replaced devices that did not trigger a full Intune sync.", "**How it''s identified:** The two co-occurring conditions—an active Endpoint Protection or Application Control policy block on the installer and a stale Intune inventory/policy state on the device—are both present. Neither condition alone fully explains the behavior; the security block prevents installation while the outdated sync prevents current approvals and entitlements from propagating."], "confidence": "high", "evidence": {"ticket_count": 21, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:59:41.158869+00:00"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/endpoint-protection-block-plus-stale-inventory';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, FinanceApp''s absence from Software Center may be related to a deployment targeting misconfiguration in the endpoint management platform that could prevent correct policy evaluation despite valid entitlement group membership.", "key_points": ["**Common pattern:** Affected users on managed Windows devices found FinanceApp v4.2.1 missing or unavailable in Software Center despite confirmed entitlement group membership; standard remediation steps such as policy retrieval cycles, restarts, and reboots did not resolve the issue, and alternative installation methods were blocked with authorization or security policy errors.", "**Scope / variation:** In one case the application was entirely absent from the catalog, possibly due to a backend targeting misconfiguration; in another, an Endpoint Protection security block additionally prevented manual installation. One affected device had a degraded management client state with stale policy data, which limited the telemetry available for diagnosis.", "**Identification:** A confirmed root cause could not be fully determined due to incomplete device management and security telemetry; the hypothesis of a deployment targeting misconfiguration remains unverified and may require further investigation with complete diagnostic data."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "unconfirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:59:48.266642+00:00"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/indeterminate-incomplete-telemetry';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is the affected user''s account missing membership in the required Entra ID or Active Directory entitlement security group used for Intune application assignment targeting.", "key_points": ["**Common pattern:** Affected users find a required business application missing from the Software Center or Company Portal catalog, or present but blocked on install with errors such as \"Entitlement check failed\" or \"Installation blocked by policy\" — despite the device being enrolled and compliant.", "**Scope / variation:** The issue manifests differently depending on environment and configuration: the app may be entirely absent, may appear only after a manual refresh but still fail, or may be blocked in both Software Center and Company Portal in co-managed environments. Multiple error codes (0x87D00231, 0x80180014, 0x87D00607, 0x87D1061E, 0xE000020B, POLICY_CHECK_FAILED) all trace to the same missing group membership. A stale Intune device sync can further delay catalog visibility."], "confidence": "high", "evidence": {"ticket_count": 11, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T19:59:55.088160+00:00"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/missing-entitlement-group-membership';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is the affected user''s Active Directory account missing from the required application entitlement security group, compounded by Endpoint Protection application control policy blocking or quarantining the installer.", "key_points": ["**Common pattern:** Affected users see \"user not entitled\" (0x80180014), \"policy check failed\" (0x87D00231 / 0x80070490), or \"entitlement not found\" errors when attempting to install an application through Software Center, while colleagues in the same role can install it without issue. Standard self-remediation steps such as cache clearing and Intune sync do not resolve the problem.", "**Scope / variation:** The issue presents in several ways — the application may be entirely absent from the Software Center catalog, visible but immediately blocked on install, or blocked by Endpoint Protection before the installer ever launches. In some cases only the missing group membership is responsible; in others, an Endpoint Protection quarantine or hash denial acts as a compounding block that must also be resolved."], "confidence": "medium", "evidence": {"ticket_count": 5, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:00:01.439834+00:00"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/missing-entitlement-group-membership-plus-endpoint-protection-block';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a combination of missing Intune entitlement group membership, stale device inventory, and Endpoint Protection application control blocking the installer — all three must be remediated together to restore application availability in Software Center.", "key_points": ["**Common pattern:** Affected users on managed Windows 10 Enterprise devices find required applications missing, intermittently visible, or persistently marked \"Blocked\" in Software Center, with errors such as \"blocked by policy\" or \"blocked by Endpoint Protection\" (and sometimes error codes 0x80070490 or 0x87D1041C). The issue persists across restarts and reboots, and fixing only one underlying factor does not resolve it.", "**Scope / variation:** The issue spans different application types (line-of-business apps, marketing tools, VPN clients) and has been observed across multiple regional offices. Presentation varies — some users see no application listing at all, while others see a persistent \"Blocked\" status. In at least one case, an Intune refresh temporarily restored visibility, but the blocked state returned after reboot because not all three factors had been addressed."], "confidence": "medium", "evidence": {"ticket_count": 7, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:00:09.158254+00:00"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/missing-entitlement-plus-endpoint-protection-and-stale-inventory';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is the user''s account missing from the required Azure AD entitlement group, compounded by a stale Intune device inventory that prevents corrected group membership from taking effect.", "key_points": ["**Common pattern:** Affected users on corporate-managed Windows endpoints find a required application missing from Software Center or listed with a greyed-out Install button; attempting installation returns an entitlement policy failure such as \"EntitlementCheckFailed\" or \"installation blocked.\" Rebooting does not resolve the issue.", "**Scope / variation:** The issue presents in several ways — the app may be entirely absent from both Software Center and Company Portal, the Install button may be disabled with an explicit error code, or a prior entitlement fix may appear to have regressed. In some cases the device shows a recent Company Portal sync timestamp yet Intune inventory remains stale and does not reflect current group membership.", "**How it''s identified:** Investigation typically reveals two overlapping factors: the user is not a member of the application-specific entitlement group in Azure AD, and the device''s Intune last-sync timestamp is 24 hours or more old — meaning even after group membership is corrected, updated policy is not reflected until a manual inventory and policy refresh is performed."], "confidence": "medium", "evidence": {"ticket_count": 5, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:00:16.162985+00:00"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/missing-entitlement-plus-stale-inventory';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause may be stale device inventory and policy state in Intune/Software Center, preventing the endpoint from recognizing valid application deployments.", "key_points": ["**Common pattern:** Affected users on Windows 10 21H2 endpoints see error 0x87D13B5C or an \"Installation blocked by policy\" message in Software Center, and targeted applications may disappear from the Available catalog despite correct Intune assignments and entitlement group membership.", "**Scope / variation:** The issue appears endpoint-specific — colleagues on other devices in the same entitlement group can install the same application without issue. The blocked application may differ between recurrences on the same device, and the app may initially appear in a stale catalog listing but fail only at installation time.", "**How it''s identified:** The condition is recognized by confirming that application targeting and user entitlement are correct while the affected endpoint alone fails to reflect current deployment metadata; the issue may recur on the same device across different applications until policy data is refreshed."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:00:22.339617+00:00"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/stale-inventory-policy-targeting-only';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is clock drift on authenticator devices generating out-of-sync TOTP codes, often compounded by stale MFA factor enrollments that prevent recovery even after time correction.", "key_points": ["**Common pattern:** Affected users enter a TOTP code from their authenticator app during SSO sign-in but are returned to the MFA prompt in a loop, blocking access to all federated SaaS applications (e.g., Office 365, Salesforce, Workday). Identity provider logs show repeated MFA challenge failures on individual accounts rather than a tenant-wide error.", "**Scope / variation:** The issue has appeared on both mobile (iPhone/iOS 16) and desktop (Windows 10) authenticator apps across multiple office locations. In some cases it followed an overnight maintenance window or a same-day mobile OS update. A single user with ~8 minutes of clock drift was affected while colleagues were not; in another case, correcting device time alone did not resolve the loop because a stale factor enrollment — some over fourteen months old — still blocked verification and required MFA reset and re-enrollment."], "confidence": "medium", "evidence": {"ticket_count": 3, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:00:29.315288+00:00"}' WHERE family = 'SML' AND root_cause_id = 'SML/authenticator-clock-drift-totp-mismatch';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is stale MFA factor enrollments on Okta accounts combined with group-based conditional access policy mismatches in Azure AD, triggered by identity sync operations or policy migrations, resulting in an indefinite SSO authentication loop across federated SaaS applications.", "key_points": ["**Common pattern:** After entering valid credentials and approving the Okta Verify MFA prompt, affected users are immediately returned to another MFA challenge instead of gaining access. The loop persists regardless of application, device, or browser cache state, and may surface errors such as \"Sign-in rejected,\" \"Authentication rejected,\" or HTTP 401 MFA_REQUIRED responses. Okta logs show repeated MFA challenges with no successful verification, while Azure AD logs show conditional access denials or token desynchronization.", "**Scope / variation:** The issue spans internal departments and external contractor groups and is account-specific—some members of the same Azure AD access group sign in normally while others loop. Variations include explicit \"access_denied\" errors instead of a silent loop, intermittent rather than complete access failure, and cases where a legacy conditional access policy referencing deprecated pre-migration factor schemas caused the loop specifically for re-enrolled users. A subset of affected users required individual MFA enrollment resets even after the policy-level fix was applied.", "**How it''s identified:** Okta system logs for affected accounts show repeated MFA challenge events with token mismatch errors and SAML assertion rejections but no successful verification callback. Azure AD sign-in logs show corresponding conditional access denials, and in some cases successful token issuance that Okta simultaneously rejects, confirming desynchronization between the two identity platforms. The issue consistently follows recent conditional access policy updates, group attribute modifications, or scheduled identity sync operations."], "confidence": "high", "evidence": {"ticket_count": 15, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:00:40.321791+00:00"}' WHERE family = 'SML' AND root_cause_id = 'SML/combined-stale-enrollment-and-policy-desync';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a group-scoping mismatch between Okta and Azure AD conditional access policies—introduced by recent admin changes—that forces repeated MFA challenges or access denials despite valid MFA enrollment.", "key_points": ["**Common pattern:** Affected users in the same organizational group encounter endless MFA prompt loops or HTTP 401/403 errors when signing in to SaaS applications through Okta SSO federated with Azure AD; Okta logs confirm successful MFA verification, but Azure AD sign-in logs show conditional access denials (e.g., error code 53003) or missing group claims.", "**Scope / variation:** The issue typically emerges after directory sync updates, group restructures, or conditional access policy changes and affects group-based cohorts rather than isolated accounts. Some users see explicit access-denied errors instead of the loop; in some cases a deprecated sign-on policy reference, authenticator device clock drift, or a location-based conditional access rule scoped to a regional group contributed to or compounded the failures. MFA factor re-enrollment resolved the issue for some users but not others in the same cohort."], "confidence": "medium", "evidence": {"ticket_count": 7, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:00:47.619213+00:00"}' WHERE family = 'SML' AND root_cause_id = 'SML/conditional-access-group-policy-mismatch';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause of the post-MFA session loop may be a misconfigured claim mapping in the Okta-to-Azure AD federation trust that omitted the contractor group claim from the SAML assertion.", "key_points": ["**Common pattern:** Affected users — specifically contractor accounts — experience a repeating MFA loop when accessing SaaS applications through the corporate SSO portal; after approving the Okta Verify push, a brief loading screen appears before returning to the MFA prompt, with the behavior starting shortly after a scheduled federation trust change window.", "**Scope:** The issue appears consistent with a federation-level fault rather than an application-specific failure; it may affect contractor accounts provisioned through a recently synced Azure AD contractor access group, and has been observed across multiple SaaS targets including Salesforce and Office 365."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:00:53.456859+00:00"}' WHERE family = 'SML' AND root_cause_id = 'SML/post-mfa-federation-session-fault';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is stale or mismatched MFA factor enrollment records in the Okta tenant, where retained factor identifiers no longer match users'' current authenticator state, triggering a continuous SSO challenge loop after MFA approval.", "key_points": ["**Common pattern:** Affected users successfully enter primary credentials and approve the MFA challenge (Okta Verify push or TOTP), but the browser immediately returns to the MFA prompt instead of granting a session. The loop persists across browsers, devices, and incognito sessions, and Okta logs show successful primary authentication followed by repeated factor challenges and token validation failures (AUTH-401, ERR_MFA_ENROLL_STALE, factor-mismatch).", "**Scope / variation:** The issue affects individual accounts and groups of up to ~14 users simultaneously, spanning multiple locations, departments, and contractor accounts. It has been observed after MFA migrations (e.g., legacy TOTP to Okta Verify push), mobile device changes, authenticator reinstallations, and directory sync events such as Azure AD Connect syncs. Some federated applications (e.g., ServiceNow) may remain accessible while others are blocked, and self-service steps like cache clearing or re-adding the authenticator do not resolve the loop.", "**How it''s identified:** Okta system logs for impacted accounts reveal successful primary authentication followed by repeated factor challenge events, token validation failures (AUTH-401, ERR_MFA_ENROLL_STALE, invalid_token, invalid_grant), and factor-mismatch errors — confirming that enrolled MFA factor identifiers no longer correspond to the users'' active authenticator instance, while access policy memberships and application assignments are verified as correct."], "confidence": "high", "evidence": {"ticket_count": 20, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:02.264864+00:00"}' WHERE family = 'SML' AND root_cause_id = 'SML/stale-mfa-factor-enrollment';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is expired device certificates on managed endpoints, which fail GlobalProtect''s post-MFA certificate validation and trigger immediate VPN tunnel teardown despite successful Okta MFA approval.", "key_points": ["**Common pattern:** Affected users complete Okta MFA successfully and briefly see a \"Connected\" status for 2–40 seconds before the GlobalProtect tunnel tears down automatically, leaving all internal resources unreachable. Repeated reconnection attempts reproduce the same cycle, and standard troubleshooting such as reboots or client restarts does not resolve it.", "**Scope / variation:** The issue affects Windows 10, Windows 11, and macOS 12 managed endpoints across multiple offices and VPN gateways. Some endpoints also carry stale VPN profiles referencing outdated certificate thumbprints, requiring both certificate renewal and profile refresh. In some cases, Windows cumulative updates prevented automatic certificate renewal, and in at least one instance an improperly re-enrolled (not expired) certificate produced the same failure.", "**How it''s identified:** Gateway and client-side logs show a TLS handshake or device certificate validation failure during the post-authentication phase, with the gateway rejecting the session due to a certificate-expired error even though user-level MFA credentials are valid. Certificate expirations often align with failed rotation windows or recent OS updates."], "confidence": "high", "evidence": {"ticket_count": 53, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:10.147359+00:00"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/expired-device-certificate-post-mfa-validation-failure';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, a possible cause may be post-authentication instability on the GlobalProtect gateway resetting VPN sessions shortly after successful MFA validation, leading to rapid disconnections across multiple users and regions.", "key_points": ["**Common pattern:** Affected users on managed Windows 10 laptops see GlobalProtect briefly reach a \"Connected\" state after approving the MFA push, then drop within three to five seconds — blocking access to internal resources such as the intranet, Confluence, and Salesforce, with the issue persisting across repeated sign-in attempts.", "**Scope:** The behavior was observed across at least five remote workers in multiple geographic locations; MFA authentication completed successfully and no endpoint certificate issues were found, which may point to a gateway-side issue rather than an endpoint or user-level problem."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:15.984053+00:00"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/gateway-portal-post-auth-instability';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, post-MFA VPN disconnects on GlobalProtect may be caused by a profile misconfiguration referencing an outdated device certificate thumbprint, leading to post-authentication policy failure.", "key_points": ["**Common pattern:** Affected users on managed Windows 10 laptops see the VPN session establish briefly (10–20 seconds) after successful MFA approval, then drop automatically; internal applications may partially load before becoming unreachable, and the issue recurs across reconnect attempts.", "**Possible cause (unverified):** A pushed GlobalProtect profile may reference an old certificate thumbprint that no longer matches the currently enrolled device certificate, which could cause post-authentication policy evaluation to fail with a VPN-ERR-201 error and terminate the tunnel."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:21.308043+00:00"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/globalprotect-profile-cert-mapping-misconfiguration';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, the cause of intermittent GlobalProtect VPN disconnections shortly after successful Okta MFA authentication may be a transient client, network, or gateway-side issue, but a single failure point could not be identified.", "key_points": ["**Common pattern:** The GlobalProtect client briefly shows a successful connection (green system tray icon) after MFA approval, then disconnects within approximately five to ten seconds, leaving internal applications unreachable. The behavior could not be reproduced consistently.", "**Ruled out so far:** Device certificate expiration or mismatch was eliminated during diagnostic review; however, remaining logs did not isolate whether the disconnect originates from transient client behavior, a network interruption, or a gateway-side event. The root cause remains unverified."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "unconfirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:27.964639+00:00"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/indeterminate-intermittent-disconnect';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, repeated GlobalProtect VPN disconnections seconds after MFA authentication may be caused by a stale local VPN profile referencing a previous device certificate after renewal.", "key_points": ["**Common pattern:** Affected users on managed Windows 10 laptops see GlobalProtect briefly show \"Connected\" for roughly 3–10 seconds before dropping; internal resources (intranet, SMB shares, email) remain unreachable, and the behavior is consistent across repeated connection attempts from the same endpoint.", "**Scope / variation:** The issue appears endpoint-specific rather than network- or account-wide; not all devices receiving the same certificate renewal are affected, and in one observed case the stale profile predated the renewed certificate by approximately two months."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:33.187096+00:00"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/stale-vpn-profile-blocking-renewed-certificate';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is incomplete propagation of the renewed EAP-TLS server certificate across all wireless controller cluster nodes after a scheduled certificate rollover, leaving some authentication paths validating against expired certificate data.", "key_points": ["**Common pattern:** Managed Windows, macOS, and Android devices simultaneously fail 802.1X/EAP-TLS authentication on the corporate Wi-Fi SSID after a scheduled certificate rotation, with errors such as \"certificate expired,\" \"certificate verification failed,\" or \"Access denied by NAC\" appearing across multiple offices, floors, and device platforms.", "**Scope / variation:** The impact varies by controller node — devices authenticating through the updated primary controller may reconnect while those served by secondary cluster members continue to fail. A subset of endpoints, especially Windows laptops with cached profiles and older Android clients, require manual Wi-Fi profile removal and re-enrollment even after the server-side certificate is corrected. Temporary NAC exceptions provide only short-lived relief and do not persist across reconnection attempts."], "confidence": "medium", "evidence": {"ticket_count": 5, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:39.704661+00:00"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/cert-rollover-incomplete-trust-propagation';
UPDATE wiki_pages SET ai_overview = '{"lead": "The cause is an expired TLS certificate on the wireless controller or RADIUS server, which fails every 802.1X EAP handshake and blocks corporate Wi-Fi authentication across all affected sites.", "key_points": ["**Common pattern:** Affected users across multiple locations see \"authentication failed,\" \"certificate expired,\" or \"secure connection failed\" errors when connecting to corporate Wi-Fi. Devices detect the SSID but fail during the 802.1X handshake; wired and guest wireless networks remain fully functional. Standard client-side steps such as rebooting, forgetting the network, or re-entering credentials do not resolve the issue.", "**Scope / variation:** The issue affects all device types (Windows, macOS, iOS, Android) and both managed and BYOD endpoints equally. It impacts EAP-TLS and EAP-PEAP authentication methods, and in multi-node RADIUS clusters all members present the same expired certificate, causing site-wide — not partial — outages. In some cases the expired certificate is an intermediate in the chain rather than the primary server certificate. After the infrastructure certificate is renewed, a subset of endpoints may require Wi-Fi profile removal and certificate re-enrollment (sometimes via MDM) to restore connectivity."], "confidence": "high", "evidence": {"ticket_count": 34, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:47.114954+00:00"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/expired-radius-controller-eap-tls-certificate';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is an incorrect Active Directory group-to-NAC policy mapping, introduced during a scheduled configuration push, that assigns authenticated corporate endpoints to a quarantine, guest, or deny profile instead of the intended corporate access policy.", "key_points": ["**Common pattern:** Managed devices (Windows, iOS, Android) successfully complete 802.1X authentication on the corporate SSID but are then placed into a quarantine or guest VLAN, lose access to internal resources, or experience repeated disconnects cycling between \"authenticating\" and \"disconnected\" states—typically following a recent NAC policy change.", "**Scope / variation:** The issue affects multiple device types and user roles (including contractors) at the same site, confirming a policy-level rather than platform-specific fault. Presentation varies: some devices receive a guest-range IP with no internal access, others see outright RADIUS rejects, and others experience intermittent EAP timeouts. Endpoint-side steps such as reprovisioning Wi-Fi profiles, renewing certificates, or rebooting do not resolve the problem."], "confidence": "medium", "evidence": {"ticket_count": 6, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:53.770908+00:00"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/incorrect-nac-policy-assignment';
UPDATE wiki_pages SET ai_overview = '{"lead": "The likely cause is a corrupted or stale corporate wireless profile retaining outdated certificate thumbprints, leading to failed 802.1X EAP-TLS negotiation and repeated NAC session drops.", "key_points": ["**Common pattern:** Affected Windows 10 laptops associate with the corporate SSID but lose network access within seconds to minutes, showing \"Connected, no network access\" or \"No Internet\"; rebooting or rejoining the network provides only temporary relief before the failure recurs.", "**Scope / variation:** The issue may affect a single endpoint or a small cluster of managed laptops on the same floor — particularly after scheduled wireless profile updates or certificate renewals. Some devices receive an outright RADIUS Access-Reject, while others connect briefly before dropping; prior certificate renewals alone may not resolve the problem if the underlying stale profile state persists."], "confidence": "medium", "evidence": {"ticket_count": 5, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:01:59.711222+00:00"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/stale-or-corrupt-client-wifi-profile';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, intermittent 802.1X Wi-Fi rejections on managed Windows laptops may be related to incomplete trust-chain restoration after a wireless controller certificate rotation, combined with stale Wi-Fi profiles or certificate bindings on some endpoints.", "key_points": ["**Common pattern:** Affected users on managed Windows laptops experience intermittent failures joining or staying on the corporate Wi-Fi SSID — devices may be rejected by NAC, fail to obtain an IP address, or drop shortly after connecting, with authentication errors or repeated reconnection attempts required.", "**Scope / variation:** The issue appears limited in scope (small groups of users per incident). Presentation varies: some devices fail immediately with an authentication error, while others connect briefly before dropping. In one incident, a controller certificate renewal restored service for only a subset of devices; certain endpoints required both certificate renewal and a Wi-Fi profile re-push via MDM. RADIUS logs showed sporadic 802.1X timeouts for specific users while neighboring devices on the same SSID connected cleanly, and even endpoints with current profiles could still experience drops — making a single root cause difficult to isolate."], "confidence": "low", "evidence": {"ticket_count": 2, "root_cause_nature": "unconfirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:02:07.282682+00:00"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/unclassified-insufficient-evidence';
UPDATE wiki_pages SET ai_overview = '{"lead": "Based on limited evidence, repeated Wi-Fi disconnections on a single floor may be linked to radio instability on specific access points issuing deauthentication events shortly after successful client association.", "key_points": ["**Common pattern:** Managed Windows 10 laptops join the corporate 5 GHz SSID successfully but are dropped within two to five minutes, cycling through reconnection and disconnection repeatedly; the issue is confined to one floor while other floors and sites remain unaffected.", "**Scope / variation:** Some affected laptops may appear connected to the SSID yet have no network access or no IP address assigned, and a subset of users may need multiple manual reconnection attempts to achieve even brief connectivity.", "**How it''s identified:** Controller-side logs from two specific APs on the affected floor may show repeated deauthentication events with reason code 6 (Class 2 frame received from nonauthenticated station), with clients bouncing between the unstable APs every one to three minutes; RADIUS authentication itself appears to complete normally."], "confidence": "low", "evidence": {"ticket_count": 1, "root_cause_nature": "confirmed"}}', ai_overview_details = '{"model": "anthropic:claude-opus-4-6", "pipeline_version": "experiment-overview-v1", "generated_at": "2026-06-27T20:02:13.942638+00:00"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/wireless-rf-controller-instability';
